import { Hono } from 'hono';
import { Context } from 'hono/types';

const app = new Hono();

app.get('/task/:taskId/audit-log', async (c: Context) => {
  const taskId = c.req.param('taskId');

  // Simulate fetching the audit log history for a task
  const auditLogHistory = await fetchAuditLogHistory(taskId);

  if (!auditLogHistory) {
    return c.json({ error: 'Task not found' }, 404);
  }

  return c.json(auditLogHistory, 200);
});

async function fetchAuditLogHistory(taskId: string): Promise<any | null> {
  // Replace this with actual logic to fetch the audit log history from your data source
  // For example, you might query a database or an external API
  const mockData = [
    { taskId: '123', action: 'created', timestamp: new Date('2023-04-01T10:00:00Z') },
    { taskId: '123', action: 'reassigned to John Doe', timestamp: new Date('2023-04-02T15:00:00Z') },
    { taskId: '123', action: 'status changed to completed', timestamp: new Date('2023-04-03T09:00:00Z') }
  ];

  return mockData.filter(log => log.taskId === taskId);
}

export default app;

